mapper.select:
SELECT COUNT(*) FROM reports
WHERE reporter_id = #{reporterId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}

SELECT r.id, r.reporter_id AS reporterId, u.nickname AS reporterNickname, r.target_type AS targetType, r.target_id AS targetId, r.reason, r.status, r.created_at AS createdAt FROM reports r LEFT JOIN users u ON r.reporter_id = u.`쉼표번호`
r.status = #{status}
ORDER BY r.created_at DESC LIMIT #{size} OFFSET #{offset}
